text:
{
  "formal_minutes": {
    "회의정보": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": [
        "Minjun",
        "Seoyeon",
        "Doyun",
        "Hara"
      ]
    },
    "confirmed_decisions": [
      {
        "category": "release_target",
        "decision": "스모크 테스트 통과를 조건으로 공개 릴리스 목표 시각은 금요일 15:00 KST로 한다.",
        "certainty": "confirmed"
      },
      {
        "category": "smoke_mismatch_handling",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경한다.",
        "result": "rejected",
        "certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스 제안은 내부 스트레치 목표로만 언급되었고 확정 일정은 아니다.",
        "certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차는 가능하면 목요일까지 검토해야 한다는 의견이 있었으나 담당자는 정해지지 않았다.",
        "certainty": "confirmed"
      },
      {
        "item": "Hara의 tarball 경로 확인은 수행하기로 했으나 정확한 완료 시각은 정해지지 않았다.",
        "certainty": "confirmed"
      }
    ],
    "risks": [
      {
        "risk": "tarball 경로가 잘못되면 릴리스가 지연될 수 있다.",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 절차가 오래되었으면 릴리스 노트가 사용자를 오도할 수 있다.",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "open",
        "certainty": "confirmed"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?",
        "status": "open",
        "certainty": "confirmed"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "미정",
      "task": "README 설치 절차를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능 시",
      "status": "owner_unassigned",
      "source_certainty": "explicit"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 스모크 테스트 통과 여부를 먼저 확인한다.",
      "스모크 실패 시 Doyun의 트리아지 노트가 action_items.md에 반영되었는지 확인한다.",
      "스모크 결과 게시 후 Hara의 tarball 경로 확인 결과를 점검한다.",
      "README 설치 절차 검토 담당자 지정 여부를 확인한다.",
      "최종 릴리스 승인 권한자 결정을 추적한다.",
      "릴리스 노트에 수요일 내부 스트레치 목표를 언급할지 여부를 별도 결정 사항으로 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "지정되지 않은 담당자",
      "명시되지 않은 마감 시각"
    ]
  },
  "non_invention_rules": [
    "인라인 합성 픽스처에 없는 고객 정보를 추가하지 않는다.",
    "예산, 보안, 장애, 법무 관련 사실을 새로 만들지 않는다.",
    "담당자와 마감은 명시된 경우만 기록하고, 미정인 경우 그대로 표시한다.",
    "확정 결정과 제안, 반려안, 내부 스트레치 목표, 리스크, 미해결 질문을 분리해 기록한다.",
    "수요일 일정은 확정 공개 릴리스가 아니라 내부 스트레치 목표로만 다룬다."
  ]
}
